def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # 'right' should be the last valid index
    while left <= right:  # Loop while pointers haven't crossed
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Search in the right half
        else:
            right = mid - 1 # Search in the left half
    return -1

